// Frontend: Firebase Auth SDK
import { initializeApp } from 'firebase/app';
import { getAuth, signInWithEmailAndPassword, signInWithPopup, GoogleAuthProvider } from 'firebase/auth';

const app = initializeApp({ apiKey: 'YOUR_KEY', authDomain: 'your-app.firebaseapp.com' });
const auth = getAuth(app);

// Email/password sign-in
async function login(email, password) {
    try {
        const cred = await signInWithEmailAndPassword(auth, email, password);
        const token = await cred.user.getIdToken();
        console.log('User:', cred.user.email, 'UID:', cred.user.uid);
        return token; // Send this to your backend
    } catch (err) {
        console.error('Auth failed:', err.code, err.message);
    }
}

// Google sign-in
async function loginWithGoogle() {
    const provider = new GoogleAuthProvider();
    const cred = await signInWithPopup(auth, provider);
    return await cred.user.getIdToken();
}

